static void init_free_list(void* memory, size_t block_size, size_t count) {
    char* ptr = (char*)memory;
    for (size_t i = 0; i < count - 1; i++) {
        *(void**)(ptr + i * block_size) = ptr + (i + 1) * block_size;
    }
    *(void**)(ptr + (count - 1) * block_size) = NULL;
}

static int ptr_in_range(void* ptr, void* start, size_t total_size) {
    return (char*)ptr >= (char*)start && 
           (char*)ptr < (char*)start + total_size;
}
